import{_ as t,c as o,o as l,a5 as a,j as e}from"./chunks/framework.Dtwt352Q.js";const h=JSON.parse('{"title":"v1.1.35: Major Performance Improvements, Server Management Added","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.35.md","filePath":"en/changelog/v1.1.35.md","lastUpdated":1772014034000}'),n={name:"en/changelog/v1.1.35.md"};function r(s,i,d,p,c,m){return l(),o("div",null,[...i[0]||(i[0]=[a('<h1 id="v1-1-35-major-performance-improvements-server-management-added" tabindex="-1">v1.1.35: Major Performance Improvements, Server Management Added <a class="header-anchor" href="#v1-1-35-major-performance-improvements-server-management-added" aria-label="Permalink to “v1.1.35: Major Performance Improvements, Server Management Added”">​</a></h1><p><strong>Release Date</strong>: January 25, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>This update significantly improves workspace creation performance, adds server management functionality, and fixes multiple user experience issues.</p><hr><h2 id="new-feature-server-management" tabindex="-1">New Feature: Server Management <a class="header-anchor" href="#new-feature-server-management" aria-label="Permalink to “New Feature: Server Management”">​</a></h2><h3 id="what-was-updated" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated" aria-label="Permalink to “What was updated?”">​</a></h3><p>Added a server management interface for easier management of OpenCode server connections.</p><h3 id="how-to-use" tabindex="-1">How to use? <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to use?”">​</a></h3><p>In the Desktop app:</p><ol><li>Open settings, find &quot;Server&quot; option</li><li>Click &quot;Manage Servers&quot; to enter the management interface</li><li>Add, delete, or edit your server configurations</li></ol><hr><h2 id="new-feature-model-configuration-improvements" tabindex="-1">New Feature: Model Configuration Improvements <a class="header-anchor" href="#new-feature-model-configuration-improvements" aria-label="Permalink to “New Feature: Model Configuration Improvements”">​</a></h2><h3 id="what-was-updated-1" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-1" aria-label="Permalink to “What was updated?”">​</a></h3><p>Improved model configuration functionality. Now you can more flexibly set parameters for Kimi K2.5 model, and added xhigh reasoning level for GitHub Copilot GPT-5 model.</p><h3 id="how-to-use-1" tabindex="-1">How to use? <a class="header-anchor" href="#how-to-use-1" aria-label="Permalink to “How to use?”">​</a></h3><ol><li>Open model settings</li><li>Select Kimi K2.5 model</li><li>Adjust recommended topP and temperature settings</li></ol><hr><h2 id="new-feature-workspace-performance-boost" tabindex="-1">New Feature: Workspace Performance Boost <a class="header-anchor" href="#new-feature-workspace-performance-boost" aria-label="Permalink to “New Feature: Workspace Performance Boost”">​</a></h2><h3 id="what-was-updated-2" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-2" aria-label="Permalink to “What was updated?”">​</a></h3><p>Significantly accelerated workspace creation speed, making new projects smoother.</p><h3 id="impact-on-you" tabindex="-1">Impact on You <a class="header-anchor" href="#impact-on-you" aria-label="Permalink to “Impact on You”">​</a></h3><p>No more long waits when creating new workspaces - a more fluid experience.</p><hr><h2 id="new-feature-support-for-multiple-new-models" tabindex="-1">New Feature: Support for Multiple New Models <a class="header-anchor" href="#new-feature-support-for-multiple-new-models" aria-label="Permalink to “New Feature: Support for Multiple New Models”">​</a></h2><h3 id="what-was-updated-3" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-3" aria-label="Permalink to “What was updated?”">​</a></h3><ul><li>Support for GPT-5.1-Codex model (in Codex auth plugin)</li><li>Support for multiple inference providers</li></ul><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Using Desktop version</td><td>✅ Recommended upgrade (noticeable performance boost)</td></tr><tr><td>Using multiple servers</td><td>✅ Recommended upgrade</td></tr><tr><td>Everything working fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade command</strong>:</p>',32),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),a('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Add tests</li><li>Sync changes from upstream</li><li>Fix models snapshot loading to prevent caching issues</li><li>Fix Nix configuration</li><li>Fix unicode filename handling in snapshot diff by disabling quote escaping</li><li>Deep merge providerOptions in applyCaching to preserve nested configuration (@zerone0x)</li><li>Construct apply_patch metadata before requesting permission in web interface (@brittlewis12)</li><li>Remove models.dev macro</li><li>Tell the model what model it is in the environment section of the prompt</li><li>Retry web fetch with simple user agent on 403 errors (@Arasple)</li><li>Allow GPT-5.1-Codex model in Codex auth plugin (@Danztee)</li><li>Bump gitlab-ai-provider version (@vglafirov)</li><li>Add model information as part of task metadata (@shantur)</li><li>Add xhigh reasoning effort for GitHub Copilot GPT-5 models (@Arthur742Ramos)</li><li>Normalize path separators for session diff filtering on Windows (@alexyaroshuk)</li><li>Faster workspace creation</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Fix question selection click when terminal is unfocused (@maharshi365)</li><li>Use min/maxHeight for question textarea</li><li>Permission prompt should ignore keyboard events while dialog stack length is greater than zero (@justfortheloveof)</li><li>Use selectedForeground for question prompt tab text visibility (@ariane-emory)</li><li>Always center selected item in selection dialogs (@ariane-emory)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Fix submit button state in app</li><li>Fix unnecessary suspense flash in app</li><li>Add active state to comment cards in prompt input</li><li>Fix type error</li><li>Terminal clone needs remount to function properly</li><li>Remove terminal connection error overlay</li><li>Remove space between ellipsis and truncated text in comment card tooltip</li><li>Update status popover empty state text color and centering</li><li>Prevent focus on share popover text field</li><li>Add link icon and use it for copy-to-clipboard buttons in UI</li><li>Adjust share popover position 64px to the left</li><li>Update share popover gutter to 6px and radius to match status dropdown</li><li>Add 8px spacing between share button and icon buttons in titlebar</li><li>Replace Popover with DropdownMenu for server options in app</li><li>Update options icon button styling with improved active state and hover effects</li><li>Change server item actions div padding from px-4 to pl-4</li><li>Add onFilter callback to List component and hide add server row during search</li><li>Position status circle inside input wrapper and fix dialog padding</li><li>Remove hover background color from server list items</li><li>Allow add server row to grow for error messages in app</li><li>Update add server button and row styling in app</li><li>Update manage servers dialog styling and behavior</li><li>Add truncation tooltip to server items in status popover</li><li>Update server and MCP item styles in status popover</li><li>Update status popover styling and positioning</li><li>Use 4px border radius (rounded-sm) consistently in app components</li><li>Update titlebar spacing and status popover styling in app</li><li>Enable submit button when comment cards are present in app</li><li>Add back button in subagent sessions (@tomzhu1024)</li><li>Model select dropdown not closing when pressing Escape key</li><li>Improve model selector user experience</li><li>Fix inability to select text when creating a new session</li><li>Fix scrolling in unpaid model selector</li><li>Fix Adam integration issue</li><li>Add critical shadow for comment input validation and set editor popover radius to 14px</li><li>Improve comment popover with better error styling and click-outside detection</li><li>Change prompt placeholder based on comment count in app</li><li>Adjust prompt container padding to 16px on bottom and horizontal sides</li><li>Adjust prompt input positioning to 12px from bottom and right edges, remove session panel bottom padding</li><li>Add escape/click-away to close read-only comment popovers, 10px radius, and remove &#39;Click to view context&#39; text</li><li>Don&#39;t use findLast in app package</li><li>Add state to pause existing audio for demo menus and add support for audio controls (@jcampuza)</li><li>Implement new server management for web and desktop (@OpeOginni)</li><li>New workspace appears expanded and at the top of the list</li><li>Missing translations in app</li><li>Better error screen when connecting to sidecar</li><li>Fix line selection issues in the app</li><li>Fixed reactive loops in the app</li><li>Better session stream rendering performance</li><li>Add Iosevka as a font choice in desktop app (@ariane-emory)</li><li>Always close hovercard when view-sessions is clicked (@DNGriffin)</li><li>Close comment input popover on Escape key or click away</li><li>Use shadow-lg-border-base on read-only comment popovers and align label spacing</li><li>Remove border from comment input popover</li><li>Position read-only comment popover below icon with 4px gutter</li><li>Style comment popovers with 14px radius, move label below comment, and adjust text colors and sizes</li><li>Move filename and line count below comment text in popovers</li><li>Add tooltip with path, 6px spacing before close icon, and reduce filename truncation to 14 characters in editor tabs</li><li>Add middle truncation for filename in comment card</li><li>Truncate filename from start to show end of path in the app</li><li>Remove gap between filename and comment in comment card</li><li>Add shadow-xs-border with hover state to comment card</li><li>Fix comment card styling with 48px height, 2px gap, and truncated filename while preserving line count visibility</li><li>Increase comment font size to 12px in the app</li><li>Add 8px gap before close icon and truncate long filenames in app</li><li>Keep close icon in top right of comment card</li><li>Add transition-all to comment card hover states</li><li>Add close-small icon and use it for comment card dismiss button</li><li>Truncate comment text and set card max-width to 200px in app</li><li>Indent comment text to align with filename in context card</li><li>Style submitted comment icons to match comment popup style</li><li>Update prompt input styling with refined borders, hover states, and spacing</li><li>Update context cards styling with 8px padding/gap and 6px border radius</li><li>Add button-primary-base variable and use primary variant for Comment button</li><li>Improve comment popup styling and add new comment icon</li><li>Center checkbox indicator in provider selection (@ProdigyRahul)</li><li>Auto-open OAuth links for Codex and Copilot (@edoedac0)</li><li>Close delete workspace dialog immediately</li><li>Don&#39;t remount directory layout in app for better performance</li><li>Reapply work in progress changes for line selection feature in app</li><li>Revert line selection work in progress</li><li>Fix view all sessions flakiness in app (@DNGriffin)</li></ul><p><strong>Thank you to 18 community contributors:</strong></p><p>@ProdigyRahul:</p><ul><li>fix(app): enable dialog dismiss on model selector (dialog.tsx) (#10203)</li><li>fix(app): center checkbox indicator in provider selection (#10267)</li><li>fix(app): tooltip text in light mode to use inverted neutral scale (#9786)</li><li>fix(app): markdown rendering with morphdom for better dom functions (#10373)</li></ul><p>@DNGriffin:</p><ul><li>fix(app): View all sessions flakiness (#10149)</li><li>fix(app): Fix plan mode btn keyboard a11y issues (#10330)</li><li>fix(app): Always close hovercard when view-sessions clicked (#10326)</li></ul><p>@shantur:</p><ul><li>docs(ecosystem): Add CodeNomad entry to ecosystem documentation (#10222)</li><li>feat(tasks): Add model info as part of metadata (#10307)</li></ul><p>@edoedac0:</p><ul><li>feat(app): auto-open oauth links for codex and copilot (#10258)</li></ul><p>@ariane-emory:</p><ul><li>feat: always center selected item in selection dialogs (resolves #10209) (#10207)</li><li>feat(desktop): add Iosevka as a font choice (resolves #10103) (#10347)</li><li>fix(tui): Use selectedForeground for question prompt tab text visibility (resolves #10334) (#10337)</li></ul><p>@alexyaroshuk:</p><ul><li>fix(app): normalize path separators for session diff filtering on Windows (#10291)</li></ul><p>@Arthur742Ramos:</p><ul><li>fix: add xhigh reasoning effort for GitHub Copilot GPT-5 models (#10092)</li></ul><p>@vglafirov:</p><ul><li>fix: bump gitlab-ai-provider version (#10255)</li></ul><p>@Danztee:</p><ul><li>fix: allow gpt-5.1-codex model in codex auth pluginFixes (#10181)</li></ul><p>@Arasple:</p><ul><li>fix: retry webfetch with simple UA on 403 (#10328)</li></ul><p>@neriousy:</p><ul><li>feat(docs): add a desktop troubleshooting guide (#10397)</li></ul><p>@justfortheloveof:</p><ul><li>fix: permission prompt should ignore keyboard events while dialog stack len &gt; 0 (#10338)</li></ul><p>@brittlewis12:</p><ul><li>fix(web): construct apply_patch metadata before requesting permission (#10422)</li></ul><p>@OpeOginni:</p><ul><li>feat(web): implement new server management for web and desktop (#8513)</li></ul><p>@zerone0x:</p><ul><li>fix(provider): deep merge providerOptions in applyCaching (#10323)</li></ul><p>@jcampuza:</p><ul><li>fix: add state to pause existing audio for demo menus, add support fo… (#10428)</li></ul><p>@maharshi365:</p><ul><li>fix(opentui): question selection click when terminal unfocused (#9731)</li></ul><p>@tomzhu1024:</p><ul><li>feat(app): back button in subagent sessions (#10439)</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const f=t(n,[["render",r]]);export{h as __pageData,f as default};
